export const getWordData = (word) =>
  [...Y1_WORD_DATA, ...Y2_WORD_DATA].find(e => e.word === word.toLowerCase()) ?? null;
export const getDefinition = (word, age = 7) => {
  const entry = getWordData(word);
  if (!entry) return null;
  return age <= 7 ? entry.definitions.ages5to7 : entry.definitions.ages7to10;
};
export const getSessionWords = ({ year = 1, difficulty = 'all', includeEarlier = true }) => {
  const pool = year === 2 && includeEarlier ? [...Y1_WORD_DATA, ...Y2_WORD_DATA] : year === 2 ? Y2_WORD_DATA : Y1_WORD_DATA;
  return pool.filter(e => difficulty === 'all' || e.difficulty === difficulty);
};
export const getWordsByPattern = (r) => [...Y1_WORD_DATA, ...Y2_WORD_DATA].filter(e => e.spellingRule === r);
export const getWordsByPatternGroup = (g) => [...Y1_WORD_DATA, ...Y2_WORD_DATA].filter(e => e.patternGroup === g);
export const getCorePatternWords = () => [...Y1_WORD_DATA, ...Y2_WORD_DATA].filter(e => e.corePatternWord);

const ks1WordData = {
  y1: { label:'Year 1', ageRange:[5,6], words:Y1_WORD_DATA, statutory:Y1_STATUTORY },
  y2: { label:'Year 2', ageRange:[6,7], words:Y2_WORD_DATA, statutory:Y2_STATUTORY },
  ks1: { label:'KS1', ageRange:[5,7], words:[...Y1_WORD_DATA,...Y2_WORD_DATA], statutory:KS1_ALL_STATUTORY },
  getWordData, getDefinition, getSessionWords, getWordsByPattern, getWordsByPatternGroup, getCorePatternWords,
};

export default ks1WordData;
